159→export interface SketchData {
160→  paper: PaperType;
161→  tool: ToolType;
162→  inkColor: string;
163→  amplitude: number;
164→  waves: number;
165→  humanness: number;
166→  width?: number;
167→  height?: number;
168→  sessionSeed?: number;
169→  elements: SketchElement[];
170→}
171→
172→export interface PaperSize {
