174→  width: number;
175→  height: number;
176→}
177→
178→export const PAPER_SIZES: Record<string, PaperSize> = {
179→  "A4+": { label: "A4+", width: 1000, height: 750 },
180→  A4: { label: "A4", width: 842, height: 595 },
181→  "A3+": { label: "A3+", width: 1400, height: 1000 },
182→  "16:9": { label: "16:9", width: 1280, height: 720 },
183→};
184→
185→export const PAPER_COLORS: Record<PaperType, string> = {
186→  cream: "#f5f0e0",
187→  white: "#ffffff",
188→  yellow: "#fffff0",
189→  blueprint: "#1a3a5c",
190→};
191→
192→export const TOOL_STYLES: Record<
193→  ToolType,
194→  { lineWidth: number; opacity: number }
195→> = {
196→  pencil: { lineWidth: 1, opacity: 0.6 },
197→  ballpoint: { lineWidth: 1.5, opacity: 0.85 },
198→  ink: { lineWidth: 2.5, opacity: 1.0 },
199→};
