  1→import {
  2→  SketchData,
  3→  SketchElement,
  4→  PAPER_COLORS,
  5→  TOOL_STYLES,
  6→  PaperType,
  7→} from "./types";
  8→import {
  9→  wobbleLine,
 10→  wobbleCircle,
 11→  wobbleArc,
 12→  drawSmoothCurve,
 13→  WobbleOptions,
 14→  Point,
 15→} from "./wobble";
 16→
 17→function getWobbleOpts(sketch: SketchData, el: SketchElement): WobbleOptions {
 18→  return {
 19→    amplitude: sketch.amplitude,
 20→    waves: sketch.waves,
 21→    humanness: sketch.humanness,
 22→    seed: hashElement(el) + (sketch.sessionSeed || 0),
 23→  };
 24→}
 25→
 26→function hashElement(el: SketchElement): number {
 27→  const str = JSON.stringify(el);
 28→  let h = 0;
 29→  for (let i = 0; i < str.length; i++) {
 30→    h = ((h << 5) - h + str.charCodeAt(i)) | 0;
 31→  }
 32→  return Math.abs(h);
 33→}
 34→
 35→function setupStroke(
 36→  ctx: CanvasRenderingContext2D,
 37→  sketch: SketchData,
 38→  el: SketchElement
 39→): void {
 40→  const tool = TOOL_STYLES[sketch.tool];
 41→  ctx.strokeStyle = el.color || sketch.inkColor || "#111";
 42→  ctx.lineWidth = el.strokeWidth || tool.lineWidth;
 43→  ctx.globalAlpha = tool.opacity;
 44→  ctx.lineCap = "round";
 45→  ctx.lineJoin = "round";
 46→}
 47→
 48→function drawWobbleLine(
 49→  ctx: CanvasRenderingContext2D,
 50→  x1: number,
 51→  y1: number,
 52→  x2: number,
 53→  y2: number,
 54→  opts: WobbleOptions
 55→): void {
 56→  const points = wobbleLine(x1, y1, x2, y2, opts);
 57→  drawSmoothCurve(ctx, points);
 58→}
 59→
 60→function drawArrowHead(
 61→  ctx: CanvasRenderingContext2D,
 62→  x: number,
 63→  y: number,
 64→  angle: number,
 65→  size: number
 66→): void {
 67→  ctx.beginPath();
 68→  ctx.moveTo(
 69→    x - size * Math.cos(angle - Math.PI / 6),
 70→    y - size * Math.sin(angle - Math.PI / 6)
 71→  );
 72→  ctx.lineTo(x, y);
 73→  ctx.lineTo(
 74→    x - size * Math.cos(angle + Math.PI / 6),
 75→    y - size * Math.sin(angle + Math.PI / 6)
 76→  );
 77→  ctx.stroke();
 78→}
 79→
 80→function drawGrid(
 81→  ctx: CanvasRenderingContext2D,
 82→  w: number,
 83→  h: number,
 84→  paper: PaperType
 85→): void {
 86→  if (paper === "yellow") {
 87→    ctx.strokeStyle = "#e8e4c8";
 88→    ctx.lineWidth = 0.5;
 89→    ctx.globalAlpha = 0.4;
 90→    const step = 25;
 91→    for (let x = step; x < w; x += step) {
 92→      ctx.beginPath();
 93→      ctx.moveTo(x, 0);
 94→      ctx.lineTo(x, h);
 95→      ctx.stroke();
 96→    }
 97→    for (let y = step; y < h; y += step) {
 98→      ctx.beginPath();
 99→      ctx.moveTo(0, y);
100→      ctx.lineTo(w, y);
101→      ctx.stroke();
102→    }
103→    ctx.globalAlpha = 1;
104→  } else if (paper === "blueprint") {
105→    ctx.strokeStyle = "#2a5a8c";
106→    ctx.lineWidth = 0.3;
107→    ctx.globalAlpha = 0.5;
108→    const step = 20;
109→    for (let x = step; x < w; x += step) {
110→      ctx.beginPath();
111→      ctx.moveTo(x, 0);
112→      ctx.lineTo(x, h);
113→      ctx.stroke();
114→    }
115→    for (let y = step; y < h; y += step) {
116→      ctx.beginPath();
117→      ctx.moveTo(0, y);
118→      ctx.lineTo(w, y);
119→      ctx.stroke();
120→    }
121→    ctx.globalAlpha = 1;
122→  }
123→}
124→
125→export function renderSketch(
126→  ctx: CanvasRenderingContext2D,
127→  sketch: SketchData,
128→  canvasWidth: number,
129→  canvasHeight: number
130→): void {
131→  const w = sketch.width || canvasWidth;
132→  const h = sketch.height || canvasHeight;
133→
134→  // Background
135→  ctx.fillStyle = PAPER_COLORS[sketch.paper] || PAPER_COLORS.cream;
136→  ctx.fillRect(0, 0, w, h);
137→
138→  // Grid for certain paper types
139→  drawGrid(ctx, w, h, sketch.paper);
140→
141→  // Default ink color for blueprint
142→  const defaultColor =
143→    sketch.paper === "blueprint" ? "#a8c8e8" : sketch.inkColor || "#111";
144→
145→  // Center elements on paper — compute bounding box and offset
146→  const bbox = computeBoundingBox(sketch.elements);
147→  let offsetX = 0;
148→  let offsetY = 0;
149→  if (bbox) {
150→    const contentW = bbox.maxX - bbox.minX;
151→    const contentH = bbox.maxY - bbox.minY;
152→    const contentCenterX = bbox.minX + contentW / 2;
153→    const contentCenterY = bbox.minY + contentH / 2;
154→    const paperCenterX = w / 2;
155→    const paperCenterY = h / 2;
156→    const dx = paperCenterX - contentCenterX;
157→    const dy = paperCenterY - contentCenterY;
158→    if (Math.abs(dx) > w * 0.05) offsetX = dx;
159→    if (Math.abs(dy) > h * 0.05) offsetY = dy;
160→  }
161→
162→  if (offsetX !== 0 || offsetY !== 0) {
163→    ctx.save();
164→    ctx.translate(offsetX, offsetY);
165→  }
166→
167→  // Render each element
168→  for (const el of sketch.elements) {
169→    ctx.save();
170→    setupStroke(ctx, sketch, { ...el, color: el.color || defaultColor });
171→    const opts = getWobbleOpts(sketch, el);
172→
173→    // Apply element rotation if specified
174→    if (el.rotation) {
175→      const center = getElementCenter(el);
176→      ctx.translate(center.x, center.y);
177→      ctx.rotate((el.rotation * Math.PI) / 180);
178→      ctx.translate(-center.x, -center.y);
179→    }
180→
181→    switch (el.type) {
182→      case "line":
183→        drawWobbleLine(ctx, el.x1, el.y1, el.x2, el.y2, opts);
184→        break;
185→
186→      case "rect": {
187→        // Four wobble lines forming a rectangle
188→        drawWobbleLine(ctx, el.x, el.y, el.x + el.w, el.y, { ...opts, seed: opts.seed! + 1 });
189→        drawWobbleLine(ctx, el.x + el.w, el.y, el.x + el.w, el.y + el.h, { ...opts, seed: opts.seed! + 2 });
190→        drawWobbleLine(ctx, el.x + el.w, el.y + el.h, el.x, el.y + el.h, { ...opts, seed: opts.seed! + 3 });
191→        drawWobbleLine(ctx, el.x, el.y + el.h, el.x, el.y, { ...opts, seed: opts.seed! + 4 });
192→        break;
193→      }
194→
195→      case "circle": {
196→        const points = wobbleCircle(el.cx, el.cy, el.r, opts);
197→        drawSmoothCurve(ctx, points, true);
198→        break;
199→      }
200→
201→      case "arc": {
202→        const arcPoints = wobbleArc(
203→          el.cx,
204→          el.cy,
205→          el.r,
206→          el.startAngle,
207→          el.endAngle,
208→          opts
209→        );
210→        drawSmoothCurve(ctx, arcPoints);
211→        break;
212→      }
213→
214→      case "arrow": {
215→        drawWobbleLine(ctx, el.x1, el.y1, el.x2, el.y2, opts);
216→        const angle = Math.atan2(el.y2 - el.y1, el.x2 - el.x1);
217→        drawArrowHead(ctx, el.x2, el.y2, angle, 10);
218→        break;
219→      }
220→
221→      case "text": {
222→        const fontSize = el.fontSize || 14;
223→        ctx.font = `${fontSize}px 'Caveat', cursive`;
224→        ctx.fillStyle = el.color || defaultColor;
225→        ctx.globalAlpha = TOOL_STYLES[sketch.tool].opacity;
226→        // Slight rotation for hand-drawn feel
227→        const rotation = (Math.sin(hashElement(el)) * sketch.humanness * 2 * Math.PI) / 180;
228→        ctx.save();
229→        ctx.translate(el.x, el.y);
230→        ctx.rotate(rotation);
231→        ctx.fillText(el.text, 0, 0);
232→        ctx.restore();
233→        break;
234→      }
235→
236→      case "dashed": {
237→        const dashLen = el.dashLength || 8;
238→        const gapLen = el.gapLength || 6;
239→        const len = Math.sqrt((el.x2 - el.x1) ** 2 + (el.y2 - el.y1) ** 2);
240→        const dx = (el.x2 - el.x1) / len;
241→        const dy = (el.y2 - el.y1) / len;
242→        let pos = 0;
243→        let segIdx = 0;
244→        while (pos < len) {
245→          const segEnd = Math.min(pos + dashLen, len);
246→          drawWobbleLine(
247→            ctx,
248→            el.x1 + dx * pos,
249→            el.y1 + dy * pos,
250→            el.x1 + dx * segEnd,
251→            el.y1 + dy * segEnd,
252→            { ...opts, seed: opts.seed! + segIdx++ }
253→          );
254→          pos = segEnd + gapLen;
255→        }
256→        break;
257→      }
258→
259→      case "dim": {
260→        // Dimension line with arrows and label
261→        const dimAngle = Math.atan2(el.y2 - el.y1, el.x2 - el.x1);
262→        drawWobbleLine(ctx, el.x1, el.y1, el.x2, el.y2, opts);
263→        drawArrowHead(ctx, el.x1, el.y1, dimAngle + Math.PI, 8);
264→        drawArrowHead(ctx, el.x2, el.y2, dimAngle, 8);
265→        // Extension lines
266→        const nx = -Math.sin(dimAngle) * 8;
267→        const ny = Math.cos(dimAngle) * 8;
268→        ctx.beginPath();
269→        ctx.moveTo(el.x1 + nx, el.y1 + ny);
270→        ctx.lineTo(el.x1 - nx, el.y1 - ny);
271→        ctx.stroke();
272→        ctx.beginPath();
273→        ctx.moveTo(el.x2 + nx, el.y2 + ny);
274→        ctx.lineTo(el.x2 - nx, el.y2 - ny);
275→        ctx.stroke();
276→        // Label — rotate text to follow the dim line, offset outward
277→        const midX = (el.x1 + el.x2) / 2;
278→        const midY = (el.y1 + el.y2) / 2;
279→        ctx.font = "12px 'Caveat', cursive";
280→        ctx.fillStyle = el.color || defaultColor;
281→        ctx.textAlign = "center";
282→        ctx.textBaseline = "bottom";
283→        const isVertical = Math.abs(el.x2 - el.x1) < Math.abs(el.y2 - el.y1);
284→        if (isVertical) {
285→          ctx.save();
286→          ctx.translate(midX, midY);
287→          ctx.rotate(-Math.PI / 2);
288→          ctx.fillText(el.label, 0, -6);
289→          ctx.restore();
290→        } else {
291→          ctx.fillText(el.label, midX, midY - 6);
292→        }
293→        break;
294→      }
295→
296→      case "window": {
297→        // Wall line with perpendicular ticks showing window
298→        drawWobbleLine(ctx, el.x1, el.y1, el.x2, el.y2, opts);
299→        const wLen = Math.sqrt((el.x2 - el.x1) ** 2 + (el.y2 - el.y1) ** 2);
300→        const wdx = (el.x2 - el.x1) / wLen;
301→        const wdy = (el.y2 - el.y1) / wLen;
302→        const wnx = -wdy * 6;
303→        const wny = wdx * 6;
304→        const tickCount = Math.max(2, Math.floor(wLen / 15));
305→        for (let i = 0; i <= tickCount; i++) {
306→          const t = i / tickCount;
307→          const px = el.x1 + wdx * wLen * t;
308→          const py = el.y1 + wdy * wLen * t;
309→          ctx.beginPath();
310→          ctx.moveTo(px - wnx, py - wny);
311→          ctx.lineTo(px + wnx, py + wny);
312→          ctx.stroke();
313→        }
314→        break;
315→      }
316→
317→      case "door-symbol": {
318→        // Door swing arc
319→        const doorW = el.w || 80;
320→        const swing = el.swing || "left";
321→        const hingeX = swing === "left" ? el.x : el.x + doorW;
322→        const startA = swing === "left" ? -90 : 180;
323→        const endA = swing === "left" ? 0 : 270;
324→        // Draw the door line
325→        const doorEndX = swing === "left" ? el.x + doorW : el.x;
326→        drawWobbleLine(ctx, hingeX, el.y, doorEndX, el.y, opts);
327→        // Draw the swing arc
328→        const arcPts = wobbleArc(hingeX, el.y, doorW, startA, endA, opts);
329→        drawSmoothCurve(ctx, arcPts);
330→        break;
331→      }
332→
333→      case "door-slide": {
334→        const dsW = el.w || 80;
335→        const dsDir = el.direction || "right";
336→        // Two parallel lines
337→        drawWobbleLine(ctx, el.x, el.y, el.x + dsW, el.y, { ...opts, seed: opts.seed! + 1 });
338→        drawWobbleLine(ctx, el.x, el.y + 4, el.x + dsW, el.y + 4, { ...opts, seed: opts.seed! + 2 });
339→        // Arrow indicating slide direction
340→        const arrowX1 = dsDir === "right" ? el.x + dsW * 0.3 : el.x + dsW * 0.7;
341→        const arrowX2 = dsDir === "right" ? el.x + dsW * 0.7 : el.x + dsW * 0.3;
342→        const arrowAngle = Math.atan2(0, arrowX2 - arrowX1);
343→        drawArrowHead(ctx, arrowX2, el.y + 2, arrowAngle, 6);
344→        break;
345→      }
346→
347→      case "stair": {
348→        const stairSteps = el.steps || 8;
349→        const stepH = el.h / stairSteps;
350→        // Outline
351→        drawWobbleLine(ctx, el.x, el.y, el.x + el.w, el.y, { ...opts, seed: opts.seed! + 100 });
352→        drawWobbleLine(ctx, el.x, el.y + el.h, el.x + el.w, el.y + el.h, { ...opts, seed: opts.seed! + 101 });
353→        drawWobbleLine(ctx, el.x, el.y, el.x, el.y + el.h, { ...opts, seed: opts.seed! + 102 });
354→        drawWobbleLine(ctx, el.x + el.w, el.y, el.x + el.w, el.y + el.h, { ...opts, seed: opts.seed! + 103 });
355→        // Treads
356→        for (let i = 1; i < stairSteps; i++) {
357→          const sy = el.y + stepH * i;
358→          drawWobbleLine(ctx, el.x, sy, el.x + el.w, sy, { ...opts, seed: opts.seed! + i });
359→        }
360→        break;
361→      }
362→
363→      case "opening": {
364→        // Gap in wall with small perpendicular returns
365→        const oLen = Math.sqrt((el.x2 - el.x1) ** 2 + (el.y2 - el.y1) ** 2);
366→        const odx = (el.x2 - el.x1) / oLen;
367→        const ody = (el.y2 - el.y1) / oLen;
368→        const returnLen = 6;
369→        const rnx = -ody * returnLen;
370→        const rny = odx * returnLen;
371→        // Left return
372→        ctx.beginPath();
373→        ctx.moveTo(el.x1 - rnx, el.y1 - rny);
374→        ctx.lineTo(el.x1 + rnx, el.y1 + rny);
375→        ctx.stroke();
376→        // Right return
377→        ctx.beginPath();
378→        ctx.moveTo(el.x2 - rnx, el.y2 - rny);
379→        ctx.lineTo(el.x2 + rnx, el.y2 + rny);
380→        ctx.stroke();
381→        break;
382→      }
383→
384→      case "column": {
385→        const colSize = el.size || 10;
386→        ctx.fillStyle = el.color || defaultColor;
387→        const colPoints = wobbleCircle(el.cx, el.cy, colSize / 2, opts);
388→        ctx.beginPath();
389→        ctx.moveTo(colPoints[0].x, colPoints[0].y);
390→        for (let i = 1; i < colPoints.length; i++) {
391→          ctx.lineTo(colPoints[i].x, colPoints[i].y);
392→        }
393→        ctx.closePath();
394→        ctx.fill();
395→        ctx.stroke();
396→        break;
397→      }
398→    }
399→
400→    ctx.restore();
401→  }
402→
403→  if (offsetX !== 0 || offsetY !== 0) {
404→    ctx.restore();
405→  }
406→}
