408→/** Returns the center point of a single element for rotation transforms */
409→function getElementCenter(el: SketchElement): { x: number; y: number } {
410→  if ("x1" in el && "x2" in el && "y1" in el && "y2" in el) {
411→    return { x: (el.x1 + el.x2) / 2, y: (el.y1 + el.y2) / 2 };
412→  }
413→  if ("cx" in el && "cy" in el) {
414→    return { x: el.cx, y: el.cy };
415→  }
416→  if ("x" in el && "y" in el && "w" in el && "h" in el) {
417→    return { x: (el as { x: number; w: number }).x + (el as { w: number }).w / 2, y: (el as { y: number; h: number }).y + (el as { h: number }).h / 2 };
418→  }
419→  if ("x" in el && "y" in el) {
420→    return { x: (el as { x: number }).x, y: (el as { y: number }).y };
421→  }
422→  return { x: 0, y: 0 };
423→}
424→
425→function computeBoundingBox(
426→  elements: SketchElement[]
427→): { minX: number; minY: number; maxX: number; maxY: number } | null {
428→  if (!elements || elements.length === 0) return null;
429→
430→  let minX = Infinity,
431→    minY = Infinity,
432→    maxX = -Infinity,
433→    maxY = -Infinity;
434→
435→  for (const el of elements) {
436→    if ("x1" in el && "x2" in el && "y1" in el && "y2" in el) {
437→      minX = Math.min(minX, el.x1, el.x2);
438→      minY = Math.min(minY, el.y1, el.y2);
439→      maxX = Math.max(maxX, el.x1, el.x2);
440→      maxY = Math.max(maxY, el.y1, el.y2);
441→    } else if ("x" in el && "w" in el && "h" in el) {
442→      minX = Math.min(minX, el.x);
443→      minY = Math.min(minY, el.y);
444→      maxX = Math.max(maxX, el.x + el.w);
445→      maxY = Math.max(maxY, el.y + el.h);
446→    } else if ("cx" in el && "r" in el) {
447→      minX = Math.min(minX, el.cx - el.r);
448→      minY = Math.min(minY, el.cy - el.r);
449→      maxX = Math.max(maxX, el.cx + el.r);
450→      maxY = Math.max(maxY, el.cy + el.r);
451→    } else if ("x" in el && "y" in el) {
452→      minX = Math.min(minX, el.x);
453→      minY = Math.min(minY, el.y - 20);
454→      maxX = Math.max(maxX, el.x + 80);
455→      maxY = Math.max(maxY, el.y);
456→    }
457→  }
458→
459→  if (!isFinite(minX)) return null;
460→  return { minX, minY, maxX, maxY };
461→}
