  6→/** Seeded random for reproducible wobble per element */
  7→function seededRandom(seed: number): () => number {
  8→  let s = seed;
  9→  return () => {
 10→    s = (s * 16807 + 0) % 2147483647;
 11→    return (s - 1) / 2147483646;
 12→  };
 13→}
