 15→export interface WobbleOptions {
 16→  amplitude: number; // 0-1, how far lines deviate
 17→  waves: number; // 0-1, frequency of wobble
 18→  humanness: number; // 0-1, randomness factor
 19→  seed?: number;
 20→}
