 27→function distance(x1: number, y1: number, x2: number, y2: number): number {
 28→  return Math.sqrt((x2 - x1) ** 2 + (y2 - y1) ** 2);
 29→}
 30→
 31→function lerp(a: number, b: number, t: number): number {
 32→  return a + (b - a) * t;
 33→}
