 35→/**
 36→ * Generate wobble points along a line from (x1,y1) to (x2,y2).
 37→ */
 38→export function wobbleLine(
 39→  x1: number,
 40→  y1: number,
 41→  x2: number,
 42→  y2: number,
 43→  opts: WobbleOptions
 44→): Point[] {
 45→  const len = distance(x1, y1, x2, y2);
 46→  if (len < 1) return [{ x: x1, y: y1 }, { x: x2, y: y2 }];
 47→
 48→  const rand = seededRandom(opts.seed ?? Math.floor(x1 * 100 + y1 * 37 + x2 * 13 + y2 * 7));
 49→  const amp = opts.amplitude * 3; // scale to pixels
 50→  const steps = Math.max(8, Math.floor(len * (0.1 + opts.waves * 0.15)));
 51→  const points: Point[] = [];
 52→
 53→  // Slight humanness offset to start/end
 54→  const hOff = opts.humanness * 2;
 55→  const sx = x1 + (rand() - 0.5) * hOff;
 56→  const sy = y1 + (rand() - 0.5) * hOff;
 57→  const ex = x2 + (rand() - 0.5) * hOff;
 58→  const ey = y2 + (rand() - 0.5) * hOff;
 59→
 60→  // Normal direction
 61→  const nx = -(y2 - y1) / len;
 62→  const ny = (x2 - x1) / len;
 63→
 64→  for (let i = 0; i <= steps; i++) {
 65→    const t = i / steps;
 66→    const bx = lerp(sx, ex, t);
 67→    const by = lerp(sy, ey, t);
 68→
 69→    // Wobble offset (zero at endpoints for clean joins)
 70→    const edgeFade = Math.sin(t * Math.PI); // fades to 0 at start/end
 71→    const wave = Math.sin(t * Math.PI * (1 + opts.waves * 4));
 72→    const offset =
 73→      wave * amp * edgeFade * (0.5 + rand() * opts.humanness * 0.5);
 74→
 75→    points.push({
 76→      x: bx + nx * offset,
 77→      y: by + ny * offset,
 78→    });
 79→  }
 80→
 81→  return points;
 82→}
