 84→/**
 85→ * Generate wobble points for a circle.
 86→ */
 87→export function wobbleCircle(
 88→  cx: number,
 89→  cy: number,
 90→  r: number,
 91→  opts: WobbleOptions
 92→): Point[] {
 93→  const rand = seededRandom(opts.seed ?? Math.floor(cx * 100 + cy * 37 + r * 13));
 94→  const circumference = 2 * Math.PI * r;
 95→  const steps = Math.max(24, Math.floor(circumference * (0.1 + opts.waves * 0.1)));
 96→  const amp = opts.amplitude * 2.5;
 97→  const points: Point[] = [];
 98→
 99→  for (let i = 0; i <= steps; i++) {
100→    const t = i / steps;
101→    const angle = t * Math.PI * 2;
102→    const wave = Math.sin(t * Math.PI * (3 + opts.waves * 6));
103→    const offset = wave * amp * (0.5 + rand() * opts.humanness * 0.5);
104→    const rr = r + offset;
105→
106→    points.push({
107→      x: cx + Math.cos(angle) * rr,
108→      y: cy + Math.sin(angle) * rr,
109→    });
110→  }
111→
112→  return points;
113→}
