115→/**
116→ * Generate wobble points for an arc.
117→ */
118→export function wobbleArc(
119→  cx: number,
120→  cy: number,
121→  r: number,
122→  startAngleDeg: number,
123→  endAngleDeg: number,
124→  opts: WobbleOptions
125→): Point[] {
126→  const rand = seededRandom(opts.seed ?? Math.floor(cx * 100 + cy * 37 + r * 13 + startAngleDeg));
127→  const startAngle = (startAngleDeg * Math.PI) / 180;
128→  const endAngle = (endAngleDeg * Math.PI) / 180;
129→  const arcLength = Math.abs(endAngle - startAngle) * r;
130→  const steps = Math.max(12, Math.floor(arcLength * (0.1 + opts.waves * 0.1)));
131→  const amp = opts.amplitude * 2;
132→  const points: Point[] = [];
133→
134→  for (let i = 0; i <= steps; i++) {
135→    const t = i / steps;
136→    const angle = lerp(startAngle, endAngle, t);
137→    const edgeFade = Math.sin(t * Math.PI);
138→    const wave = Math.sin(t * Math.PI * (2 + opts.waves * 4));
139→    const offset = wave * amp * edgeFade * (0.5 + rand() * opts.humanness * 0.5);
140→    const rr = r + offset;
141→
142→    points.push({
143→      x: cx + Math.cos(angle) * rr,
144→      y: cy + Math.sin(angle) * rr,
145→    });
146→  }
147→
148→  return points;
149→}
