151→/**
152→ * Draw a smooth curve through points on a canvas context.
153→ */
154→export function drawSmoothCurve(
155→  ctx: CanvasRenderingContext2D,
156→  points: Point[],
157→  closed: boolean = false
158→): void {
159→  if (points.length < 2) return;
160→
161→  ctx.beginPath();
162→  ctx.moveTo(points[0].x, points[0].y);
163→
164→  if (points.length === 2) {
165→    ctx.lineTo(points[1].x, points[1].y);
166→    ctx.stroke();
167→    return;
168→  }
169→
170→  // Use quadratic curves for smoothness
171→  for (let i = 1; i < points.length - 1; i++) {
172→    const midX = (points[i].x + points[i + 1].x) / 2;
173→    const midY = (points[i].y + points[i + 1].y) / 2;
174→    ctx.quadraticCurveTo(points[i].x, points[i].y, midX, midY);
175→  }
176→
177→  if (closed) {
178→    const midX = (points[points.length - 1].x + points[0].x) / 2;
179→    const midY = (points[points.length - 1].y + points[0].y) / 2;
180→    ctx.quadraticCurveTo(
181→      points[points.length - 1].x,
182→      points[points.length - 1].y,
183→      midX,
184→      midY
185→    );
186→    ctx.closePath();
187→  } else {
188→    const last = points[points.length - 1];
189→    ctx.lineTo(last.x, last.y);
190→  }
191→
192→  ctx.stroke();
193→}
