 32→  const bp=0.15+rng()*0.7;
 33→  const env=t=>Math.min(1,Math.pow(Math.max(t,0.001)/bp,.55))*Math.min(1,Math.pow(Math.max(1-t,0.001)/(1-bp),.55));
